sql:
SELECT c.country_name, c.country_code, c.total_olympic_medals
FROM countries c
WHERE c.total_olympic_medals > 100;

SELECT game_code, SUM(total_athletes) AS total_participants, SUM(total_countries) AS total_participating_countries
FROM olympic_games
GROUP BY game_code;

